#!/bin/bash set -e # Launch the TestNG XML creator Swing GUI. # Working directory is appium/ (set by run config).
CP=$(mvn -s ../k8infra/settings-local.xml dependency:build-classpath -Dmdep.outputFile=/dev/stdout -q 2>/dev/null) CP="target/classes:target/test-classes:${CP}"
exec java -cp "${CP}" qa.ios.util.CreateXml
